import { heroLogos } from "../constant/data";
import { motion } from "motion/react";

const Hero = () => {
  return (
    <section id="home" className="container section !pt-10 flex flex-col items-center text-center">
      <div className="bg-white px-6 py-3 rounded-full flex items-center gap-2 shadow-sm border border-gray-100 mb-8 relative">
        <div className="w-12 h-12 bg-orange-70/20 rounded-full flex items-center justify-center -ml-4">
          <img src="/images/shape-1.png" alt="shape" className="w-6 h-6 object-contain" />
        </div>
        <span className="font-semibold text-2xl"><span className="text-orange-50">Unlock</span> Your Creative Potential</span>
      </div>

      <h1 className="text-4xl md:text-5xl lg:text-6xl font-semibold mb-6 max-w-4xl leading-tight">
        with Online Design and Development Courses.
      </h1>
      <p className="text-gray-500 mb-10 max-w-3xl text-lg">
        Learn from Industry Experts and Enhance Your Skills.
      </p>

      <div className="flex flex-col sm:flex-row gap-4 mb-20">
        <button className="primary-btn">Explore Courses</button>
        <button className="secondary-btn">View Pricing</button>
      </div>

      <div className="w-full bg-white rounded-xl shadow-sm border border-gray-100 p-8">
        <div className="flex flex-wrap items-center justify-center gap-8 md:gap-16">
          {heroLogos.map((logo) => (
            <img 
              key={logo.id} 
              src={logo.item} 
              alt="Partner Logo" 
              style={{ width: logo.width }} 
              className="opacity-50 hover:opacity-100 grayscale hover:grayscale-0 transition-all duration-300 object-contain"
            />
          ))}
        </div>
      </div>
    </section>
  );
};

export default Hero;
